function statsEq(g, n, res, soloVs) {
  var pts=0, gf=0, gc=0, pj=0;
  for (var i=0; i<PGRP.length; i++) {
    var p=PGRP[i];
    if (p.g!==g) continue;
    var r=res[pk(p)];
    if (!r) continue;
    if (p.loc.n!==n && p.vis.n!==n) continue;
    if (soloVs) {
      var rival=p.loc.n===n?p.vis.n:p.loc.n, found=false;
      for (var j=0; j<soloVs.length; j++) if(soloVs[j]===rival){ found=true; break; }
      if (!found) continue;
    }
    pj++;
    if (p.loc.n===n) { gf+=r.l; gc+=r.v; if(r.l>r.v) pts+=3; else if(r.l===r.v) pts+=1; }
    else             { gf+=r.v; gc+=r.l; if(r.v>r.l) pts+=3; else if(r.l===r.v) pts+=1; }
  }
  return { pts:pts, gf:gf, gc:gc, dg:gf-gc, pj:pj };
}

function grupoCompleto(g, res) {
  var parts=partsDeGrupo(g);
  for (var i=0; i<parts.length; i++) if(!res[pk(parts[i])]) return false;
  return true;
}

function resolverEmp(g, eqs, res, om) {
  if (!om) om={};
  if (eqs.length<=1) return { equipos:eqs, alerta:false };
  var noms=eqs.map(function(e){ return e.n; });
  var enr=eqs.map(function(eq) {
    var rivals=noms.filter(function(n){ return n!==eq.n; });
    var dir=statsEq(g,eq.n,res,rivals), gen=statsEq(g,eq.n,res);
    return { n:eq.n, d_pts:dir.pts, d_dg:dir.dg, d_gf:dir.gf, g_dg:gen.dg, g_gf:gen.gf };
  });
  enr.sort(function(a,b){
    return (b.d_pts-a.d_pts)||(b.d_dg-a.d_dg)||(b.d_gf-a.d_gf)||(b.g_dg-a.g_dg)||(b.g_gf-a.g_gf)||
           ((om[g+'_'+a.n]||99)-(om[g+'_'+b.n]||99));
  });
  var alerta=false;
  for (var i=0; i<enr.length-1; i++) {
    var aa=enr[i], bb=enr[i+1];
    if (aa.d_pts===bb.d_pts&&aa.d_dg===bb.d_dg&&aa.d_gf===bb.d_gf&&aa.g_dg===bb.g_dg&&aa.g_gf===bb.g_gf) {
      var ma=om[g+'_'+aa.n], mb=om[g+'_'+bb.n];
      if (ma===undefined||mb===undefined||ma===mb) { alerta=true; break; }
    }
  }
  return { equipos:enr.map(function(e){ return {n:e.n}; }), alerta:alerta };
}

function clasificarGrupo(g, res, om) {
  if (!om) om={};
  var base=GRP[g].eq.map(function(eq){ var st=statsEq(g,eq.n,res); return {n:eq.n,pts:st.pts,gf:st.gf,gc:st.gc,dg:st.dg,pj:st.pj}; });
  base.sort(function(a,b){ return b.pts-a.pts; });
  var final=[], hayA=false, i=0;
  while (i<base.length) {
    var j=i+1;
    while (j<base.length&&base[j].pts===base[i].pts) j++;
    if (j-i>1) {
      var r2=resolverEmp(g,base.slice(i,j),res,om);
      if (r2.alerta) hayA=true;
      for (var k=0; k<r2.equipos.length; k++) final.push(r2.equipos[k]);
    } else final.push(base[i]);
    i=j;
  }
  return { equipos:final, alerta:hayA };
}

function calcClasif(res, om) {
  if (!om) om={};
  var cl={_alertas:{}}, terceros=[], gs=GRP_KEYS;
  for (var i=0; i<gs.length; i++) {
    var g=gs[i];
    if (grupoCompleto(g,res)) {
      var r=clasificarGrupo(g,res,om), eq=r.equipos;
      if (r.alerta) {
        cl[g]={1:'',2:'',3:''}; cl._alertas[g]=true;
      } else {
        cl[g]={1:eq[0]?eq[0].n:'',2:eq[1]?eq[1].n:'',3:eq[2]?eq[2].n:''};
        if (eq[2]) { var st=statsEq(g,eq[2].n,res); terceros.push({g:g,n:eq[2].n,pts:st.pts,dg:st.dg,gf:st.gf}); }
      }
    } else cl[g]={1:'',2:'',3:''};
  }
  // Determine m3 manual order prefix from om keys
  var m3ctx='FormM3';
  var omKeys=Object.keys(om||{});
  for(var ki=0;ki<omKeys.length;ki++){ if(omKeys[ki].indexOf('RealM3_')===0){m3ctx='RealM3';break;} }
  terceros.sort(function(a,b){
    return (b.pts-a.pts)||(b.dg-a.dg)||(b.gf-a.gf)||
           ((om[m3ctx+'_'+a.g]||99)-(om[m3ctx+'_'+b.g]||99));
  });
  cl._m3=[]; cl._m3grupos=[];
  for (var i=0; i<Math.min(8,terceros.length); i++) { cl._m3.push(terceros[i].n); cl._m3grupos.push(terceros[i].g); }
  cl._m3completo=gs.every(function(g){ return grupoCompleto(g,res); });
  return cl;
}

function asignarTerceros(cl) {
  var g8=cl._m3grupos;
  if (!g8||g8.length<8) return {};
  var key=g8.slice().sort().join(','), asign=FIFA_T495[key];
  if (!asign) return {};
  var ge={};
  for (var i=0; i<g8.length; i++) ge[g8[i]]=cl._m3[i];
  var result={};
  for (var i=0; i<HUECOS_M3.length; i++) result[HUECOS_M3[i].rid]=ge[asign[HUECOS_M3[i].slot]]||'';
  return result;
}

function ganP(eqL, eqV, res) {
  if (!res||res.l===undefined||res.v===undefined) return '';
  if (res.l>res.v) return eqL;
  if (res.v>res.l) return eqV;
  if (res.pl!=null&&res.pv!=null&&res.pl!==res.pv) return res.pl>res.pv?eqL:eqV;
  return '';
}

function buildRC(cuadro, cl) {
  var rc={ _m3asign:cl._m3completo?asignarTerceros(cl):{} };
  for (var ri=0; ri<RONDAS.length; ri++) {
    var ronda=RONDAS[ri];
    for (var pi=0; pi<ronda.partidos.length; pi++) {
      var p=ronda.partidos[pi], rid=ronda.key+'_'+p.id;
      var eL=resolverH(p.lo,cl,rc)||'', eV=resolverH(p.vo,cl,rc)||'';
      var sv=cuadro[rid];
      if (eL&&eV&&sv&&sv.l!==undefined)
        rc[rid]={ l:sv.l, v:sv.v, pl:sv.pl, pv:sv.pv, gan:ganP(eL,eV,sv), eqL:eL, eqV:eV };
    }
  }
  return rc;
}

function resolverH(o, cl, rc) {
  if (!o) return '';
  var mG=o.match(/^([12])([A-L])$/);
  if (mG) return (cl[mG[2]]&&cl[mG[2]][mG[1]])||'';
  var mM3=o.match(/^m3([A-L]+)$/);
  if (mM3) {
    var sm={
      'ABCDF':'d16_d02','CDFGH':'d16_d05','CEFHI':'d16_d07','EHIJK':'d16_d08',
      'BEFIJ':'d16_d09','AEHIJ':'d16_d10','EFGIJ':'d16_d13','DEIJL':'d16_d15'
    };
    return (rc._m3asign&&rc._m3asign[sm[mM3[0].slice(2)]])||'';
  }
  if (o.charAt(0)==='G'||o.charAt(0)==='P') {
    var esG=o.charAt(0)==='G', pid=o.slice(1);
    for (var ri=0; ri<RONDAS.length; ri++) {
      var ronda=RONDAS[ri], part=null;
      for (var pi=0; pi<ronda.partidos.length; pi++) if(ronda.partidos[pi].id===pid){ part=ronda.partidos[pi]; break; }
      if (!part) continue;
      var r=rc[ronda.key+'_'+pid];
      if (!r||!r.gan) return '';
      if (esG) return r.gan;
      var eL=resolverH(part.lo,cl,rc), eV=resolverH(part.vo,cl,rc);
      return r.gan===eL?eV:eL;
    }
  }
  return '';
}

function calcPts(p, state) {
  var pts=0, ex=0, sg=0, huecos={d16:0,oct:0,qrt:0,sem:0,ter:0,fin:0};
  var gk=Object.keys(p.grupos||{});
  for (var i=0; i<gk.length; i++) {
    var pr=p.grupos[gk[i]], r=state.resultados[gk[i]];
    if (!r) continue;
    if (pr.l===r.l&&pr.v===r.v)                                          { pts+=PTS.ex; ex++; }
    else if (Math.sign(pr.l-pr.v)===Math.sign(r.l-r.v))                 { pts+=PTS.sg; sg++; }
  }
  var clP=calcClasif(p.grupos||{},p.ordenManualForm||{}); clP._res=p.grupos||{}; var rcP=buildRC(p.cuadro||{},clP);
  // state-based calc:
  var clR=calcClasif(state.resultados, state.ordenManualReal||{}); var rcR=buildRC(state.cuadroReal, clR);
  for (var ri=0; ri<RONDAS.length; ri++) {
    var ronda=RONDAS[ri];
    for (var pi=0; pi<ronda.partidos.length; pi++) {
      var part=ronda.partidos[pi], rid=ronda.key+'_'+part.id;
      var prR=p.cuadro&&p.cuadro[rid], rrR=state.cuadroReal[rid];
      if (prR&&rrR&&prR.l!==undefined&&rrR.l!==undefined) {
        if (prR.l===rrR.l&&prR.v===rrR.v)                               { pts+=PTS.ex; ex++; }
        else if (Math.sign(prR.l-prR.v)===Math.sign(rrR.l-rrR.v))      { pts+=PTS.sg; sg++; }
      }
      var eLP=resolverH(part.lo,clP,rcP), eLR=resolverH(part.lo,clR,rcR);
      if (eLP&&eLR&&eLP===eLR) { pts+=PTS_R[ronda.key]; huecos[ronda.key]++; }
      var eVP=resolverH(part.vo,clP,rcP), eVR=resolverH(part.vo,clR,rcR);
      if (eVP&&eVR&&eVP===eVR) { pts+=PTS_R[ronda.key]; huecos[ronda.key]++; }
    }
  }
  if (state.campeonReal  && ((p.cuadro&&p.cuadro['fin_f01']&&p.cuadro['fin_f01'].gan)||p.campeon||'')=== state.campeonReal)                                           pts+=PTS.camp;
  if (state.balonReal    && p.balon    && p.balon.toLowerCase()   ===state.balonReal.toLowerCase())    pts+=PTS.balon;
  if (state.goleadorReal && p.goleador && p.goleador.toLowerCase()===state.goleadorReal.toLowerCase()) pts+=PTS.gol;
  if (state.golesReal!=null&&p.golesBota!=null&&p.golesBota===state.golesReal)                        pts+=PTS.ngol;
  return { pts:pts, ex:ex, sg:sg, h16:huecos.d16, h8:huecos.oct, h4:huecos.qrt, hs:huecos.sem, hf:huecos.fin };
}


// Exportar función principal
module.exports = { calcPts, calcClasif, buildRC, resolverH };
